## Predict P-gp substrate probability using the Random Forest model
##
## Traverses each of the 100 decision trees in \code{.pgp_rf_trees} and
## averages the leaf probabilities. No external ML packages are required;
## the trees are stored as parallel arrays and traversed with native R loops.
##
## @param mw Numeric vector. Molecular weight.
## @param logp Numeric vector. LogP (ALogP from CDK).
## @param tpsa Numeric vector. Topological polar surface area.
## @param hbd Numeric vector. Number of H-bond donors.
## @param hba Numeric vector. Number of H-bond acceptors.
## @param rb Numeric vector. Number of rotatable bonds.
## @param heavy Numeric vector. Number of heavy atoms.
## @param arom Numeric vector. Number of aromatic heavy atoms.
## @param mr Numeric vector. Molar refractivity.
## @return Numeric vector of probabilities (0 to 1). Values >= 0.5 are
##   classified as P-gp substrates ("Yes").
## @references Breiman, L. (2001). Random Forests. \emph{Machine Learning},
##   45(1), 5-32.
## @keywords internal
..predict_pgp <- function(mw, logp, tpsa, hbd, hba, rb, heavy, arom, mr) {

  n <- length(mw)
  if (n == 0) return(numeric(0))

  ## Build feature matrix (rows = molecules, cols = descriptors)
  x <- cbind(mw, logp, tpsa, hbd, hba, rb, heavy, arom, mr)

  ## For each molecule, average the prediction across all trees
  probs <- numeric(n)

  for (i in seq_len(n)) {
    xi <- x[i, , drop = TRUE]

    ## If any descriptor is NA, we cannot traverse the trees — return NA
    if (any(is.na(xi))) {
      probs[i] <- NA_real_
      next
    }

    tree_sum <- 0

    for (tree in .pgp_rf_trees) {
      node <- 1  ## R is 1-indexed
      while (tree$feature[node] != 0) {
        feat_idx <- tree$feature[node]
        if (xi[feat_idx] <= tree$threshold[node]) {
          node <- tree$left[node] + 1  ## convert from 0-indexed
        } else {
          node <- tree$right[node] + 1
        }
      }
      tree_sum <- tree_sum + tree$value[node]
    }

    probs[i] <- tree_sum / length(.pgp_rf_trees)
  }

  probs
}
